import { createRequestQueue } from './task14';

describe('createRequestQueue', () => {
  it('executes requests in order', () => {
    const results: number[] = [];
    const queue = createRequestQueue(100);
    queue.add(() => { results.push(1); });
    queue.add(() => { results.push(2); });
    queue.add(() => { results.push(3); });
    expect(results).toEqual([1, 2, 3]);
  });

  it('tracks total executed', () => {
    const queue = createRequestQueue(100);
    queue.add(() => {});
    queue.add(() => {});
    expect(queue.totalExecuted).toBe(2);
  });
});
